// Solution
function validate(compose_file) {
  const lines = compose_file.split('\n');
  const serviceSection = lines.find(line => line.trim().startsWith('service:'));
  if (serviceSection === undefined) return false;
  const serviceData = serviceSection.trim().split('\n').slice(1).join('\n');
  const [_, ports, environment] = serviceData.trim().split('\n');
  const portMappings = ports.trim().split('  ').map(port => port.trim().split(':')[0]);
  const envVars = environment.trim().split('  ').map(env => env.trim().split('=')[0]);
  return portMappings.every(port => port.includes(':')) && envVars.every(env => env.includes('=));
}

