class Solution:
    def validate(self, compose_file: str) -> bool:
        lines = compose_file.split('\n')
        service_section = lines.find(line => line.strip().startswith('service:'))
        if service_section is None:
            return False
        service_data = service_section.strip().split('\n').slice(1).join('\n')
        _, ports, environment = service_data.strip().split('\n')
        port_mappings = ports.strip().split('  ').map(lambda x: x.strip().split(':')[0])
        env_vars = environment.strip().split('  ').map(lambda x: x.strip().split('=')[0])
        return all(port in port_mappings for port in env_vars) and all(':' in port for port in port_mappings)
